import { redirect } from "next/navigation";
import { Chat } from "./components/chat";
import { nanoid } from "nanoid";
import { getRoomLabel } from "./utils/room-label";
import { Header } from "./components/header/header";
import { cookies } from "next/headers";
import { Metadata } from "next";
import { Intro } from "./components/intro";

export async function generateMetadata({
  searchParams: { roomId },
}: {
  searchParams: { [key: string]: string };
}): Promise<Metadata> {
  const roomLabel = getRoomLabel(roomId);

  return {
    title: `${roomLabel} | AnyCable Next.js Demo`,
    openGraph: {
      images: [
        {
          url: `/api/og/?roomLabel=${roomLabel}`,
          width: 1200,
          height: 630,
        },
      ],
    },
  };
}

export default function Home({
  searchParams,
}: {
  searchParams: { [key: string]: string };
}) {
  if (!searchParams.roomId) {
    return redirect(`/?roomId=${nanoid()}`);
  }
  const showIntro = !cookies().get("introShown")?.value;

  async function introShownAction() {
    "use server";

    cookies().set("introShown", "1");
  }

  return (
    <>
      <Chat
        username={cookies().get("username")!.value}
        header={<Header roomLabel={getRoomLabel(searchParams.roomId)} />}
      />
      <Intro showIntro={showIntro} introShownAction={introShownAction} />
    </>
  );
}

import { NextResponse, type NextRequest } from "next/server";
import { identifier } from "./app/api/cable";

export async function middleware(request: NextRequest) {
  const token = request.cookies.get("token")?.value;

  if (token) {
    try {
      await identifier.verify(token);
      return;
    } catch (e) {
      console.log(e);
    }
  }

  const url = new URL(request.url);
  url.pathname = "/auth";

  return NextResponse.redirect(url);
}

export const config = {
  matcher: "/",
};

import { cookies } from "next/headers";
import { RoomActions } from "./room-actions";
import { redirect } from "next/navigation";
import { nanoid } from "nanoid";
import { AvatarActions } from "./avatar-actions";

export function Header({ roomLabel }: { roomLabel: string }) {
  const username = cookies().get("username")?.value!;

  async function signOut() {
    "use server";

    cookies().delete("token");
    cookies().delete("username");
    return redirect("/auth");
  }

  return (
    <div className="rounded-b-lg border-gray-200 bg-white p-4 shadow-md">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <RoomActions newRoomId={nanoid()} />
          <div className="flex flex-col">
            <div className="text-2xs uppercase text-gray-500">Room</div>
            <div className="truncate font-semibold">{roomLabel}</div>
          </div>
        </div>
        <div>
          <AvatarActions usernameOrEmail={username} signOutAction={signOut} />
        </div>
      </div>
    </div>
  );
}

